	/**
	 * Reads the body stream into a Buffer.
	 *
	 * Throws an "AbortError" DOMException if the browser frame has already been torn down, as
	 * there is then no async task manager left that can safely bound and cancel the read.
	 *
	 * @returns Buffer.
	 */
	async #readBody(): Promise<Buffer> {
		const window = this[PropertySymbol.window];
		const asyncTaskManager = new WindowBrowserContext(window).getAsyncTaskManager();

		if (!asyncTaskManager) {
			throw new window.DOMException(
				'Failed to read response body: The operation was aborted.',
				DOMExceptionNameEnum.abortError
			);
		}

		return await FetchBodyUtility.consumeBodyStream(window, asyncTaskManager, this, () =>
			this.signal[PropertySymbol.abort]()
		);
	}
