import Browser from '../src/browser/Browser.js';
import { ReadableStream } from 'stream/web';

describe('repro', () => {
	it('response.text() rejects with AbortError on page close', async () => {
		const browser = new Browser();
		const page = browser.newPage();
		const window = page.mainFrame.window;

		const stream = new ReadableStream({
			start() {
				// Never enqueues or closes - simulates a stalled network body.
			}
		});

		const response = new window.Response(stream);
		const promise = response.text();

		await new Promise((resolve) => setTimeout(resolve, 50));

		await page.close();

		try {
			await promise;
			console.log('RESOLVED (no error) - unexpected');
		} catch (error) {
			console.log('REJECTED with:', error?.name, error?.message);
			expect(error?.name).toBe('AbortError');
		}

		await browser.close();
	}, 10000);

	it('response.text() resolves normally when not interrupted', async () => {
		const browser = new Browser();
		const page = browser.newPage();
		const window = page.mainFrame.window;

		const response = new window.Response('hello world');
		const text = await response.text();
		expect(text).toBe('hello world');

		await browser.close();
	});

	it('fully buffered response body remains readable after shutdown', async () => {
		const browser = new Browser();
		const page = browser.newPage();
		const window = page.mainFrame.window;

		const response = new window.Response('hello world');

		await browser.close();

		const text = await response.text();
		expect(text).toBe('hello world');
	});

	it('request.formData() rejects with AbortError on page close (multipart)', async () => {
