		const stream = new ReadableStream({
			start() {}
		});

		const request = new window.Request('http://localhost/', {
			method: 'POST',
			body: stream,
			headers: { 'Content-Type': 'multipart/form-data; boundary=---x' },
			duplex: 'half'
		});

		const promise = request.formData();

		await new Promise((resolve) => setTimeout(resolve, 50));
		await page.close();

		try {
			await promise;
			console.log('RESOLVED (no error) - unexpected');
		} catch (error) {
			console.log('REJECTED with:', error?.name, error?.message);
			expect(error?.name).toBe('AbortError');
		}

		await browser.close();
	}, 10000);
});
