describe('FetchBodyUtility', () => {
	describe('consumeBodyStream()', () => {
		it('Resolves with the consumed body when the read is not interrupted.', async () => {
			const window = new Window();
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(Buffer.from('Hello World'));
					controller.close();
				}
			});
			const requestOrResponse = {
				body: stream,
				[PropertySymbol.aborted]: false,
				[PropertySymbol.error]: null
			};
			const asyncTaskManager = <any>{
				startTask: () => 1,
				endTask: () => {}
			};

			const buffer = await FetchBodyUtility.consumeBodyStream(
				window,
				asyncTaskManager,
				requestOrResponse
			);

			expect(buffer.toString()).toBe('Hello World');
		});

		it('Rejects with an AbortError DOMException and cancels the reader when the async task is aborted.', async () => {
			const window = new Window();
			let cancelReason: Error | null = null;
			const stream = new ReadableStream({
				start() {
					// Never enqueues or closes - simulates a stalled network body.
				},
				cancel(reason) {
					cancelReason = reason;
				}
			});
			const requestOrResponse = {
				body: stream,
				[PropertySymbol.aborted]: false,
				[PropertySymbol.error]: null
			};
			let abortHandler: (() => void) | null = null;
			const asyncTaskManager = <any>{
				startTask: (handler: () => void) => {
					abortHandler = handler;
					return 1;
				},
				endTask: () => {}
			};

			const promise = FetchBodyUtility.consumeBodyStream(window, asyncTaskManager, requestOrResponse);

			// Lets the reader.read() call start before simulating the abort.
			await new Promise((resolve) => setImmediate(resolve));

			expect(abortHandler).not.toBeNull();
			abortHandler!();

			let error: Error | null = null;

			try {
				await promise;
			} catch (e) {
				error = <Error>e;
			}

			expect(error?.name).toBe('AbortError');
			expect(requestOrResponse[PropertySymbol.aborted]).toBe(true);
			expect(cancelReason).not.toBeNull();
		});

		it('Calls the provided "onAbort" callback in addition to cancelling the reader.', async () => {
			const window = new Window();
			const stream = new ReadableStream({
				start() {}
			});
			const requestOrResponse = {
				body: stream,
				[PropertySymbol.aborted]: false,
				[PropertySymbol.error]: null
			};
			let abortHandler: (() => void) | null = null;
			const asyncTaskManager = <any>{
				startTask: (handler: () => void) => {
					abortHandler = handler;
					return 1;
				},
				endTask: () => {}
			};
			let onAbortCalled = false;

			const promise = FetchBodyUtility.consumeBodyStream(
				window,
				asyncTaskManager,
				requestOrResponse,
				() => (onAbortCalled = true)
			);

			await new Promise((resolve) => setImmediate(resolve));

			abortHandler!();

			await promise.catch(() => {});

			expect(onAbortCalled).toBe(true);
		});
	});
});
