import type Document from '../../src/nodes/document/Document.js';
import Window from '../../src/window/Window.js';
import { ReadableStream } from 'stream/web';
import { beforeEach, describe, it, expect } from 'vitest';

describe('Response (interrupted by page close)', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('text()', () => {
		it('Rejects with an AbortError DOMException when reading the body after the page has already been closed.', async () => {
			const response = new window.Response(
				new ReadableStream({
					start(controller) {
						controller.enqueue('Hello World');
						controller.close();
					}
				})
			);

			await window.happyDOM.close();

			let error: Error | null = null;

			try {
				await response.text();
			} catch (e) {
				error = <Error>e;
			}

			expect(error).toEqual(
				new window.DOMException(
					'Failed to read response body: The operation was aborted.',
					DOMExceptionNameEnum.abortError
				)
			);
		});

		it('Remains readable after the page has been closed when the body is fully buffered.', async () => {
			const response = new window.Response('Hello World');

			await window.happyDOM.close();

			const text = await response.text();

			expect(text).toBe('Hello World');
		});
	});

	describe('formData()', () => {
		it('Rejects with an AbortError DOMException when parsing a multipart body after the page has already been closed.', async () => {
			const response = new window.Response(
				new ReadableStream({
					start(controller) {
						controller.enqueue('irrelevant, never parsed');
						controller.close();
					}
				}),
				{ headers: { 'Content-Type': 'multipart/form-data; boundary=----test' } }
			);

			await window.happyDOM.close();

			let error: Error | null = null;

			try {
				await response.formData();
			} catch (e) {
				error = <Error>e;
			}

			expect(error).toEqual(
				new window.DOMException(
					'Failed to read response body: The operation was aborted.',
					DOMExceptionNameEnum.abortError
				)
			);
		});

		it('Remains readable after the page has been closed when the multipart body is fully buffered.', async () => {
			const formData = new window.FormData();
			formData.append('some', 'test');
			const response = new window.Response(formData);

			await window.happyDOM.close();

			const formDataResponse = await response.formData();

			expect(formDataResponse.get('some')).toBe('test');
		});
	});
});
