import * as PropertySymbol from '../../../src/PropertySymbol.js';

describe('FetchBodyUtility', () => {
	describe('consumeBodyStream()', () => {
		it('Resolves with the consumed body when the read is not interrupted.', async () => {
			const window = new Window();
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(Buffer.from('Hello World'));
					controller.close();
				}
			});
			const requestOrResponse = {
				body: stream,
				[PropertySymbol.aborted]: false,
				[PropertySymbol.error]: null
			};

			const buffer = await FetchBodyUtility.consumeBodyStream(window, requestOrResponse);

			expect(buffer.toString()).toBe('Hello World');
		});

		it('Populates the "readerHolder" with the stream reader once it has been created.', async () => {
			const window = new Window();
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(Buffer.from('Hello World'));
					controller.close();
				}
			});
			const requestOrResponse = {
				body: stream,
				[PropertySymbol.aborted]: false,
				[PropertySymbol.error]: null
			};
			const readerHolder: { reader: ReadableStreamDefaultReader | null } = { reader: null };

			await FetchBodyUtility.consumeBodyStream(window, requestOrResponse, readerHolder);

			expect(readerHolder.reader).not.toBeNull();
		});

		it('Rejects with an AbortError DOMException when the "aborted" flag is set and the reader is cancelled while a read is pending.', async () => {
			const window = new Window();
			let cancelReason: Error | null = null;
			const stream = new ReadableStream({
				start() {
					// Never enqueues or closes - simulates a stalled network body.
				},
				cancel(reason) {
					cancelReason = reason;
				}
			});
			const requestOrResponse = {
				body: stream,
				[PropertySymbol.aborted]: false,
				[PropertySymbol.error]: null
			};
			const readerHolder: { reader: ReadableStreamDefaultReader | null } = { reader: null };

			const promise = FetchBodyUtility.consumeBodyStream(window, requestOrResponse, readerHolder);

			// Lets the reader.read() call start before simulating the abort.
			await new Promise((resolve) => setImmediate(resolve));

			requestOrResponse[PropertySymbol.aborted] = true;
			readerHolder.reader?.cancel(new Error('aborted')).catch(() => {});

			let error: Error | null = null;

			try {
				await promise;
			} catch (e) {
				error = <Error>e;
			}

			expect(error?.name).toBe('AbortError');
			expect(cancelReason).not.toBeNull();
		});
	});
});
